const t={hostControl:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Управляйте Linux-хостом принтера — проверяйте его состояние и состояние операционной системы и управляйте его фоновыми службами. Очистка диска и системные настройки появятся в следующих фазах."}},view:{monitor:{t:0,b:{t:2,i:[{t:3}],s:"Монитор"}},services:{t:0,b:{t:2,i:[{t:3}],s:"Службы"}},cleanup:{t:0,b:{t:2,i:[{t:3}],s:"Очистка"}}},help:{title:{t:0,b:{t:2,i:[{t:3}],s:"Что это?"}},body:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind работает на небольшом Linux-компьютере принтера (хосте). Эта панель показывает текущее состояние этой машины и её ОС, чтобы вы замечали проблемы — перегрев процессора, заполненный диск, несинхронизированные часы — не открывая терминал, и позволяет управлять фоновыми службами, которые она запускает."}},step1:{t:0,b:{t:2,i:[{t:3}],s:"Бегло просматривайте карточки температуры процессора, памяти, диска и сети."}},step2:{t:0,b:{t:2,i:[{t:3}],s:"Следите за таблицей самых нагружающих процессов, чтобы видеть, что использует процессор сейчас."}},step3:{t:0,b:{t:2,i:[{t:3}],s:"Оставьте автообновление включённым для живого вида или отключите его и обновляйте вручную."}},topics:{glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Используемые здесь термины"}}},monitor:{title:{t:0,b:{t:2,i:[{t:3}],s:"Чтение монитора"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Здесь всё только для чтения. Полосы становятся янтарными после 75 % и красными после 90 %. Температура процессора становится янтарной при 70 °C и красной при 80 °C. Предупреждение о троттлинге появляется только на платах, которые его сообщают (в основном Raspberry Pi)."}}},services:{title:{t:0,b:{t:2,i:[{t:3}],s:"Управление службами"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Каждая строка — служба systemd. Нажмите на неё, чтобы запустить/остановить/перезапустить, включить/отключить при загрузке, замаскировать, прочитать её журнал или — для служб, которые вы установили сами — удалить её unit-файл. Остановка или отключение службы требует подтверждения. Критические и защищённые службы отмечены; защищённые (такие как SSH и эта панель) нельзя остановить, чтобы вы не заблокировали себе доступ."}}},cleanup:{title:{t:0,b:{t:2,i:[{t:3}],s:"Освобождение места на диске"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Каждая строка сначала сканируется, чтобы показать, сколько она освободит. Отметьте те, что нужно очистить, и подтвердите. Предлагаются только восстановимые данные — кэш загрузок apt, старый журнал systemd, ~/.cache, ваши старые файлы в /tmp и ротированные (неактивные) логи. Ваши G-code, таймлапсы и конфигурации никогда не затрагиваются."}}}},glossary:{host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Хост"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Небольшой Linux-компьютер (например, Raspberry Pi или BTT CB1), на котором работают Klipper, Moonraker и FilaMind — отдельный от микроконтроллеров принтера."}}},load:{term:{t:0,b:{t:2,i:[{t:3}],s:"Средняя нагрузка"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Сколько процессов ожидали выполнения, усреднённо за 1 / 5 / 15 минут. Грубо: значение около числа ядер означает, что процессор занят; значительно выше — что он перегружен."}}},swap:{term:{t:0,b:{t:2,i:[{t:3}],s:"Подкачка (swap)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Дисковое пространство, используемое как резерв, когда заканчивается ОЗУ. Активное использование подкачки замедляет хост — признак нехватки памяти."}}},throttle:{term:{t:0,b:{t:2,i:[{t:3}],s:"Троттлинг"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Когда плата снижает скорость, чтобы защитить себя — обычно из-за слабого питания (просадка напряжения) или перегрева. Сообщается в основном на Raspberry Pi."}}},ntp:{term:{t:0,b:{t:2,i:[{t:3}],s:"NTP / синхронизация часов"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Протокол сетевого времени поддерживает точность часов хоста. Несинхронизированные часы могут нарушить таймлапсы, журналы и TLS-сертификаты."}}},locale:{term:{t:0,b:{t:2,i:[{t:3}],s:"Локаль"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Настройки языка и раскладки клавиатуры хоста, используемые ОС для текста, дат и раскладки клавиатуры консоли."}}},service:{term:{t:0,b:{t:2,i:[{t:3}],s:"Служба (юнит)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Фоновая программа, управляемая systemd — Klipper, Moonraker, стример веб-камеры и сетевой стек — все работают как службы."}}},enabled:{term:{t:0,b:{t:2,i:[{t:3}],s:"Включена / отключена"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Запускается ли служба автоматически при загрузке. «enabled» запускается при загрузке; «disabled» — нет; «static» запускается только другой службой."}}},mask:{term:{t:0,b:{t:2,i:[{t:3}],s:"Маскирование (mask)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Более сильная форма отключения — служба вообще не может быть запущена (даже другой службой), пока не будет размаскирована. Используйте с осторожностью."}}}}},monitor:{refresh:{t:0,b:{t:2,i:[{t:3}],s:"Обновить"}},autoRefresh:{t:0,b:{t:2,i:[{t:3}],s:"Автообновление"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Чтение состояния хоста…"}},host:{t:0,b:{t:2,i:[{t:3}],s:"Хост"}},hostname:{t:0,b:{t:2,i:[{t:3}],s:"Имя хоста"}},distro:{t:0,b:{t:2,i:[{t:3}],s:"ОС"}},kernel:{t:0,b:{t:2,i:[{t:3}],s:"Ядро"}},uptime:{t:0,b:{t:2,i:[{t:3}],s:"Время работы"}},cpu:{t:0,b:{t:2,i:[{t:3}],s:"Процессор"}},temp:{t:0,b:{t:2,i:[{t:3}],s:"Температура"}},load:{t:0,b:{t:2,i:[{t:3}],s:"Нагрузка (1·5·15 мин)"}},cores:{t:0,b:{t:2,i:[{t:3}],s:"Ядра"}},throttled:{t:0,b:{t:2,i:[{t:3}],s:"Троттлинг"}},memory:{t:0,b:{t:2,i:[{t:3}],s:"Память"}},ram:{t:0,b:{t:2,i:[{t:3}],s:"ОЗУ"}},swap:{t:0,b:{t:2,i:[{t:3}],s:"Подкачка"}},disk:{t:0,b:{t:2,i:[{t:3}],s:"Диск"}},network:{t:0,b:{t:2,i:[{t:3}],s:"Сеть"}},iface:{t:0,b:{t:2,i:[{t:3}],s:"Интерфейс"}},ip:{t:0,b:{t:2,i:[{t:3}],s:"IP-адрес"}},ssid:{t:0,b:{t:2,i:[{t:3}],s:"Wi-Fi"}},signal:{t:0,b:{t:2,i:[{t:3}],s:"Сигнал"}},timeLocale:{t:0,b:{t:2,i:[{t:3}],s:"Время и локаль"}},timezone:{t:0,b:{t:2,i:[{t:3}],s:"Часовой пояс"}},ntp:{t:0,b:{t:2,i:[{t:3}],s:"Синхронизация часов"}},synced:{t:0,b:{t:2,i:[{t:3}],s:"Синхронизировано"}},syncing:{t:0,b:{t:2,i:[{t:3}],s:"Синхронизация…"}},ntpOff:{t:0,b:{t:2,i:[{t:3}],s:"Выключено"}},language:{t:0,b:{t:2,i:[{t:3}],s:"Язык"}},keymap:{t:0,b:{t:2,i:[{t:3}],s:"Раскладка"}},topProcesses:{t:0,b:{t:2,i:[{t:3}],s:"Самые нагружающие процессы"}},command:{t:0,b:{t:2,i:[{t:3}],s:"Команда"}},cpuPct:{t:0,b:{t:2,i:[{t:3}],s:"ЦП %"}},memPct:{t:0,b:{t:2,i:[{t:3}],s:"ОЗУ %"}},pid:{t:0,b:{t:2,i:[{t:3}],s:"PID"}}},services:{warning:{t:0,b:{t:2,i:[{t:3}],s:"Остановка или отключение не той службы может вывести принтер из сети. Критические службы отмечены; защищённые нельзя остановить."}},search:{t:0,b:{t:2,i:[{t:3}],s:"Поиск служб…"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Обновить"}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Загрузка списка служб…"}},loadingDetail:{t:0,b:{t:2,i:[{t:3}],s:"Чтение службы…"}},loadingLogs:{t:0,b:{t:2,i:[{t:3}],s:"Чтение журнала…"}},summary:{t:0,b:{t:2,i:[{t:4,k:"total"},{t:3,v:" служб · "},{t:4,k:"active"},{t:3,v:" активно · "},{t:4,k:"failed"},{t:3,v:" с ошибкой"}]}},filter:{all:{t:0,b:{t:2,i:[{t:3}],s:"Все"}},active:{t:0,b:{t:2,i:[{t:3}],s:"Активные"}},inactive:{t:0,b:{t:2,i:[{t:3}],s:"Неактивные"}},failed:{t:0,b:{t:2,i:[{t:3}],s:"С ошибкой"}},enabled:{t:0,b:{t:2,i:[{t:3}],s:"Включённые"}}},stateActive:{t:0,b:{t:2,i:[{t:3}],s:"Активна"}},stateInactive:{t:0,b:{t:2,i:[{t:3}],s:"Неактивна"}},stateFailed:{t:0,b:{t:2,i:[{t:3}],s:"Ошибка"}},critical:{t:0,b:{t:2,i:[{t:3}],s:"Критическая"}},protected:{t:0,b:{t:2,i:[{t:3}],s:"Защищённая"}},state:{t:0,b:{t:2,i:[{t:3}],s:"Состояние"}},startup:{t:0,b:{t:2,i:[{t:3}],s:"Автозапуск"}},unitFile:{t:0,b:{t:2,i:[{t:3}],s:"Unit-файл"}},action:{start:{t:0,b:{t:2,i:[{t:3}],s:"Запустить"}},stop:{t:0,b:{t:2,i:[{t:3}],s:"Остановить"}},restart:{t:0,b:{t:2,i:[{t:3}],s:"Перезапустить"}},enable:{t:0,b:{t:2,i:[{t:3}],s:"Включить"}},disable:{t:0,b:{t:2,i:[{t:3}],s:"Отключить"}},mask:{t:0,b:{t:2,i:[{t:3}],s:"Замаскировать"}},unmask:{t:0,b:{t:2,i:[{t:3}],s:"Размаскировать"}}},actionOk:{t:0,b:{t:2,i:[{t:4,k:"action"},{t:3,v:": готово."}]}},confirmAction:{t:0,b:{t:2,i:[{t:4,k:"action"},{t:3,v:" «"},{t:4,k:"name"},{t:3,v:"»?"}]}},confirmYes:{t:0,b:{t:2,i:[{t:3}],s:"Да, выполнить"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Отмена"}},deleteUnit:{t:0,b:{t:2,i:[{t:3}],s:"Удалить unit-файл…"}},deletePrompt:{t:0,b:{t:2,i:[{t:3,v:"Это навсегда удалит unit-файл. Введите «"},{t:4,k:"name"},{t:3,v:"» для подтверждения."}]}},deleteConfirm:{t:0,b:{t:2,i:[{t:3}],s:"Удалить навсегда"}},deleted:{t:0,b:{t:2,i:[{t:3}],s:"Unit-файл удалён."}},logs:{t:0,b:{t:2,i:[{t:3}],s:"Недавний журнал"}},noLogs:{t:0,b:{t:2,i:[{t:3}],s:"Нет вывода журнала."}}},cleanup:{subtitle:{t:0,b:{t:2,i:[{t:3}],s:"Отметьте, что удалить, и очистите. Только кэши и старые логи — ваши печати и конфигурации в безопасности."}},rescan:{t:0,b:{t:2,i:[{t:3}],s:"Пересканировать"}},scanning:{t:0,b:{t:2,i:[{t:3}],s:"Сканирование диска…"}},na:{t:0,b:{t:2,i:[{t:3}],s:"н/д"}},items:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" файлов"}]}},freed:{t:0,b:{t:2,i:[{t:3,v:"Освобождено "},{t:4,k:"size"},{t:3,v:"."}]}},selectedTotal:{t:0,b:{t:2,i:[{t:3,v:"Выбрано: "},{t:4,k:"size"}]}},clean:{t:0,b:{t:2,i:[{t:3}],s:"Очистить выбранное"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"Удалить выбранные элементы?"}},confirmYes:{t:0,b:{t:2,i:[{t:3}],s:"Да, очистить"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Отмена"}},running:{t:0,b:{t:2,i:[{t:3}],s:"Очистка…"}},targets:{apt:{label:{t:0,b:{t:2,i:[{t:3}],s:"Кэш пакетов"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Загруженные файлы .deb, которые apt больше не нужны."}}},journal:{label:{t:0,b:{t:2,i:[{t:3}],s:"Системный журнал"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Старые логи systemd — урезаются до последних 50 МБ."}}},cache:{label:{t:0,b:{t:2,i:[{t:3}],s:"Кэш пользователя"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Восстановимые файлы в ~/.cache (миниатюры, pip и т. п.)."}}},tmp:{label:{t:0,b:{t:2,i:[{t:3}],s:"Временные файлы"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Ваши собственные файлы в /tmp старше суток."}}},logs:{label:{t:0,b:{t:2,i:[{t:3}],s:"Ротированные логи"}},desc:{t:0,b:{t:2,i:[{t:3}],s:"Старые ротированные логи Klipper/Moonraker (активный сохраняется)."}}}}}}};export{t as default};
